INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Public Secrets Monitoring$q$, $q$Continuously scans public GitHub activity in real time for exposed customer secrets, the original capability the company was founded on.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$ggshield CLI$q$, $q$Command-line tool that runs secret detection locally via pre-commit and pre-push git hooks, plus Developer Endpoint Protection for scanning developer machines.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$450+ secret detectors$q$, $q$Specific and generic detectors covering cloud keys, database credentials, private keys, and vendor tokens, combined with entropy analysis.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$NHI Governance$q$, $q$Inventories non-human identities such as service accounts and API keys, tracks permissions and usage, and recommends prioritized remediation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Honeytokens$q$, $q$Decoy credentials planted across code and endpoints that trigger instant, attributed alerts if an attacker attempts to use them.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$CI/CD and SCM integrations$q$, $q$Native support for GitHub, GitLab, Bitbucket, and Azure DevOps, with SARIF export into GitHub Advanced Security's code-scanning alerts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Remediation playbooks$q$, $q$Guided workflows to help teams revoke, rotate, and remediate exposed credentials quickly.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Self-hosted deployment$q$, $q$Enterprise customers can run GitGuardian on their own infrastructure for data residency or compliance requirements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Real-time public GitHub monitoring gives an early-warning capability few competitors offer$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Broad detector library covering 450+ secret types with low false-positive tuning options$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$NHI governance and honeytokens extend value beyond simple scanning into ongoing identity security$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Strong integration coverage across major source control and CI/CD platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Free tier is genuinely usable for small teams up to 25 developers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Business and Enterprise pricing is not publicly published, requiring a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Historical detections are capped at 500 on the free plan, limiting visibility into older leaks$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Advanced features like NHI Governance and self-hosted deployment are Enterprise-only$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Can generate alert volume that requires tuning to avoid fatigue in large codebases$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Open-source alternatives like Gitleaks and TruffleHog offer core scanning for free indefinitely$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Is GitGuardian free to use?$q$, $q$Yes, GitGuardian offers a free Starter plan for up to 25 developers with unlimited real-time scanning and up to 500 historical detections, no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Who founded GitGuardian?$q$, $q$GitGuardian was founded in 2017 in Paris, France, by Eric Fourrier and Jeremy Thomas.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$How much has GitGuardian raised in funding?$q$, $q$GitGuardian has raised approximately 118 million dollars across five rounds, including a 50 million dollar Series C in February 2026 led by investors such as Insight Partners and Eurazeo.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$What is NHI Governance in GitGuardian?$q$, $q$NHI Governance is GitGuardian's module for inventorying non-human identities like service accounts and API keys, tracking their permissions and usage, and guiding credential rotation and remediation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$What are the main alternatives to GitGuardian?$q$, $q$Common alternatives include the open-source scanners Gitleaks and TruffleHog, GitHub's built-in secret scanning and push protection, and vendors like Aikido Security, Spectral, and Legit Security.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Does GitGuardian support self-hosted deployment?$q$, $q$Yes, self-hosted deployment is available on the Enterprise plan for organizations with data residency or compliance requirements.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Preventing secret leaks in CI/CD pipelines$q$, $q$Security teams integrate GitGuardian into build pipelines to block deployments that contain hardcoded credentials before they reach production.$q$, $q$DevSecOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Monitoring for public exposure$q$, $q$Organizations use Public Secrets Monitoring to get alerted the moment an employee or contractor accidentally pushes a company secret to a public repository.$q$, $q$Security operations teams at mid-size to large enterprises$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Non-human identity lifecycle management$q$, $q$Enterprises use NHI Governance and honeytokens to inventory service accounts and API keys, rotate stale credentials, and detect attacker use of decoy credentials.$q$, $q$Cloud security and identity teams in regulated industries$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Starter (Free)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 25 developers","Unlimited real-time scanning","Up to 500 historical detections","Git hooks for developer workstations","10,000 API calls per month","Self-service support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Business$q$, $q$Custom quote$q$, $q$Annual (typical)$q$, NULL, $q$["26-200 developers","Remediation playbooks","Up to 20 teams","Custom regex detectors","SAML SSO","100,000 API calls per month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual (typical)$q$, NULL, $q$["200+ developers","Public Secrets Monitoring","NHI Governance with honeytokens","Self-hosted deployment option","Unlimited teams and API calls","Dedicated support channel"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GitGuardian is a Paris-based code security company founded in 2017 by Eric Fourrier and Jeremy Thomas, built around detecting hardcoded secrets such as API keys, passwords, and tokens in source code before attackers can exploit them.$q$, $q$The platform grew from a real-time public GitHub monitoring engine into a full non-human identity security suite covering private repositories, CI/CD pipelines, container images, chat tools, and developer workstations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GitGuardian detects more than 450 types of secrets using a combination of regex pattern matching, entropy analysis, and specific and generic detectors, with SARIF output for GitHub Advanced Security integration.$q$, $q$NHI Governance and honeytoken deception technology extend the platform beyond detection into non-human identity inventory, credential rotation, and attacker attribution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GitGuardian offers a free tier for up to 25 developers, with Business and Enterprise tiers priced on a custom, quote basis depending on developer count, deployment model, and feature requirements.$q$, $q$Enterprise customers can also opt for self-hosted deployment, unlimited API calls, and a dedicated support channel.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f79bb617-e492-4f3f-b2e0-6a6ffd43dc71', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Full git history scanning$q$, $q$Scans the entire commit history of a repository, not just the latest state, to catch secrets that were committed and later removed.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$160+ built-in detectors$q$, $q$Regex and entropy-based rules covering AWS keys, GitHub tokens, private SSH keys, database connection strings, and more.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Single Go binary$q$, $q$Ships as a self-contained static binary with no server or account required, simplifying installation across platforms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Pre-commit hook support$q$, $q$Integrates with pre-commit frameworks to block secrets from ever being committed locally.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$SARIF output$q$, $q$Produces SARIF-format results that plug directly into GitHub Advanced Security code-scanning alerts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Docker image$q$, $q$Official Docker image with over 16 million pulls simplifies use in CI/CD pipelines and containerized workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Custom rule configuration$q$, $q$Supports custom TOML-based rule configuration for organization-specific secret patterns.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Stdin scanning$q$, $q$Can scan arbitrary piped input, not just files, for flexible use in scripts and other tooling.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$No account, server, or data sharing required; runs entirely locally or in your own CI$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Full git history scanning catches secrets removed from the current commit but still present in history$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Large, well-established rule set with strong community adoption and SARIF/GitHub integration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Lightweight single binary that is easy to install and script$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$No hosted dashboard, incident management, or remediation workflow out of the box$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Development pace has slowed since founder Zach Rice shifted focus to Truffle Security in 2023$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Project governance is in transition, with the founder announcing reduced control over the repository and a successor project, Betterleaks, in 2026$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$No secret validity checking to confirm whether a detected credential is still active$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$No official commercial support or SLA for enterprise users$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Is Gitleaks free?$q$, $q$Yes, Gitleaks is completely free and open source under the MIT license, with no paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Who created Gitleaks?$q$, $q$Gitleaks was created by Zachary (Zach) Rice as a side project in 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Can Gitleaks scan git history, not just the latest commit?$q$, $q$Yes, Gitleaks scans the full commit history of a repository, which helps detect secrets that were committed in the past and later removed.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$What is Betterleaks and how does it relate to Gitleaks?$q$, $q$Betterleaks is a successor project launched by Gitleaks creator Zach Rice in March 2026, sponsored by Aikido Security, built as a more accurate rewrite using parallelized scanning and BPE tokenization-based detection.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$How is Gitleaks different from GitGuardian?$q$, $q$Gitleaks is a free, self-hosted command-line scanner with no dashboard or hosted service, while GitGuardian is a commercial platform with a free tier that adds hosted monitoring, incident workflows, NHI governance, and public repository monitoring.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Does Gitleaks integrate with GitHub's code scanning?$q$, $q$Yes, Gitleaks can output results in SARIF format, which integrates directly with GitHub Advanced Security's code-scanning alerts.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$CI pipeline secret scanning$q$, $q$Developers add Gitleaks as a CI step to automatically fail builds when hardcoded secrets are detected in new commits.$q$, $q$Individual developers and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Pre-commit protection$q$, $q$Teams wire Gitleaks into pre-commit hooks so secrets are caught and blocked before they are ever committed locally.$q$, $q$Open-source maintainers and cost-sensitive teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Historical repository audits$q$, $q$Security-conscious teams run Gitleaks against a repository's full git history to find secrets that were leaked and later removed but remain retrievable.$q$, $q$Security engineers auditing legacy codebases$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited scanning","Full git history support","160+ built-in detectors","SARIF output","Docker image and native binaries","MIT license, self-hosted"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gitleaks is a free, open-source secret scanner created by Zach Rice in 2018 and released under the MIT license, distributed as a single Go binary that scans git repositories, files, and directories for hardcoded credentials.$q$, $q$It has grown into one of the most widely adopted secret-scanning tools on GitHub, though its founder's attention shifted after joining Truffle Security in 2023, leading to the announcement of a successor project called Betterleaks in 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gitleaks combines regex pattern matching and entropy analysis to detect over 160 secret types, and it can scan full git commit history rather than only the current working tree.$q$, $q$SARIF output integrates directly with GitHub code-scanning alerts, and the tool ships as a Docker image and native binaries for pre-commit hooks and CI pipelines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gitleaks is completely free and open source under the MIT license, with no paid tiers, subscriptions, or hosted dashboard offered by the original project.$q$, $q$Organizations needing a hosted dashboard, remediation workflows, or support typically pair Gitleaks with or migrate to a commercial platform.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0db8e4b7-3129-43e3-bd36-cff6d52f51bc', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Unified customer timeline$q$, $q$Every interaction a customer has ever had across channels lives on one continuous timeline instead of separate tickets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Gladly Hero$q$, $q$The core agent workspace where human agents handle voice, chat, email, and SMS conversations with full customer context.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Gladly Sidekick$q$, $q$AI and no-code automation platform, built from the Thankful acquisition, that resolves routine inquiries like returns and order status without a human agent.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Omnichannel voice and messaging$q$, $q$Native support for phone, chat, email, SMS, and social messaging within a single interface.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Agent matching and routing$q$, $q$Routes conversations to the agent best suited to the customer or issue, rather than a generic queue.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Customer profile and lifetime value view$q$, $q$Surfaces order history, past conversations, and customer value directly in the agent view.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Self-service and automation$q$, $q$Sidekick can fully resolve common requests without human involvement, reducing overall contact volume.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Reporting and analytics$q$, $q$Dashboards for tracking agent performance, resolution rates, and customer experience metrics.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Ticketless, timeline-based model gives agents full customer context without repeat explanations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Tight integration between human-agent (Hero) and AI automation (Sidekick) products$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Strong reputation among consumer and e-commerce brands that prioritize service as a loyalty driver$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Well-funded with roughly 208 million dollars raised, supporting continued AI investment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Usage-based small-business option available through Shopify for smaller merchants$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$No free plan and no publicly available free trial for the core enterprise platform$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Relatively high per-agent pricing, starting around 180 dollars per agent per month$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Minimum seat commitments (10 agents on Hero, 45 on Superhero) exclude very small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Voice and SMS usage are often billed separately on top of the base subscription$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Pricing is not fully transparent and requires a sales conversation for most customers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$How much does Gladly cost?$q$, $q$Gladly's Hero plan typically starts around 180 dollars per agent per month billed annually with a 10-agent minimum, while the Superhero tier is about 210 dollars per user per month with a 45-user minimum; a separate usage-based small-business plan exists via the Shopify App Store.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Who founded Gladly?$q$, $q$Gladly was founded in 2014 in San Francisco by Michael Wolfe, Joseph Ansanelli, and Dirk Kessler.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$What is Gladly Sidekick?$q$, $q$Gladly Sidekick is Gladly's generative AI and no-code automation platform, built from its acquisition of Thankful, that resolves common customer inquiries like returns and order status without a human agent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Does Gladly offer a free trial?$q$, $q$Gladly's core enterprise platform does not publicly advertise a free trial; the small-business plan on Shopify offers a 30-day free trial before usage-based billing begins.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$What makes Gladly different from Zendesk or Intercom?$q$, $q$Gladly is built around a single, continuous customer timeline across all channels rather than discrete tickets, which it argues gives agents better context and turns service into a relationship-building function.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$How much funding has Gladly raised?$q$, $q$Gladly has raised approximately 208 million dollars from investors including Greylock Partners, New Enterprise Associates, GGV Capital, and AXA Venture Partners.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Consumer brand customer service$q$, $q$Retail and e-commerce brands use Gladly to unify voice, chat, email, and SMS support into one agent workspace with full customer history.$q$, $q$Customer service leaders at consumer and e-commerce brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$AI-driven contact deflection$q$, $q$Companies use Gladly Sidekick to automatically resolve high-volume, routine requests like order status and returns without agent involvement.$q$, $q$Support operations teams managing high contact volume$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Small merchant support automation$q$, $q$Smaller e-commerce merchants use Gladly's Shopify app for usage-based AI resolutions and agent seats without a large enterprise contract.$q$, $q$Small to mid-size Shopify merchants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Hero$q$, $q$$180/agent/month$q$, $q$Annual, 10-agent minimum$q$, NULL, $q$["Unified customer timeline","Omnichannel voice, chat, email, SMS","Agent routing and matching","Reporting and analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Superhero$q$, $q$$210/user/month$q$, $q$Annual, 45-user minimum$q$, NULL, $q$["Everything in Hero","Expanded enterprise features and support","Higher usage and integration limits"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$Small Business (Shopify)$q$, $q$$120/agent seat/month + usage$q$, $q$Monthly, usage-based with spend cap$q$, NULL, $q$["30-day free trial","$1.50 per AI resolution","$0.25 per AI assist","Configurable spend cap"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gladly is a customer service platform founded in 2014 in San Francisco by Michael Wolfe, Joseph Ansanelli, and Dirk Kessler, built around a single continuous customer timeline instead of ticket queues.$q$, $q$The company has raised roughly 208 million dollars in funding and grew significantly after acquiring the AI automation company Thankful, which became the foundation of Gladly Sidekick.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gladly's unified timeline gives agents full cross-channel context for every customer across voice, email, chat, SMS, and social messaging in one continuous view.$q$, $q$Gladly Sidekick, born from the Thankful acquisition, adds generative AI and no-code automation to resolve common inquiries like returns and order status without human agents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gladly's core Hero plan starts at approximately 180 dollars per agent per month billed annually with a 10-agent minimum, while the Superhero tier runs around 210 dollars per user per month with a 45-user minimum.$q$, $q$A separate, usage-based small-business plan is available through the Shopify App Store with a 30-day free trial and per-resolution AI pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4ff1377-e0f5-4af0-9e80-71487c351c04', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Self-hosted, privacy-first core$q$, $q$Runs entirely on the user's own Raspberry Pi, NAS, or Docker host, keeping home data off third-party clouds by default.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Open protocol support$q$, $q$Native support for Zigbee, Z-Wave, Matter, and MQTT alongside dedicated integrations for brands like Shelly, Sonos, and Tuya.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Automation and scenario engine$q$, $q$Build rules and scenarios that react to time, presence, or sensor data across connected devices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Encrypted remote access (Gladys Plus)$q$, $q$End-to-end encrypted access to the home instance from outside the home network without manual port forwarding.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$AI conversational control$q$, $q$Open-weight AI model integration lets users talk to their home setup in natural language.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$MCP server support$q$, $q$Model Context Protocol integration allows AI agents to interact with the Gladys instance in a structured way.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Energy monitoring$q$, $q$Enedis integration provides detailed electricity usage tracking for users in France.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Official Raspberry Pi Imager listing$q$, $q$Gladys is available as a one-click install image directly inside the official Raspberry Pi Imager tool.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Core platform is fully free, open source, and self-hosted with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Strong privacy-first design keeps home data on the user's own hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Supports a wide range of open protocols and third-party device integrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Official listing in the Raspberry Pi Imager tool simplifies installation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Gladys Plus is affordable relative to typical smart home cloud subscriptions$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Smaller integration library and community than the dominant open-source competitor, Home Assistant$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Requires self-hosting hardware and some technical comfort to set up and maintain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Encrypted remote access and camera streaming require the paid Gladys Plus subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Some features, like Enedis energy tracking, are most useful to users based in France$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Small team size (roughly 5 to 10 people) limits pace of feature development compared to larger projects$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Is Gladys Assistant free?$q$, $q$Yes, the core Gladys Assistant platform is free and open source, self-hosted on your own Raspberry Pi, NAS, or Docker host with no subscription required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Who created Gladys Assistant?$q$, $q$Gladys Assistant was created in 2013 by Pierre-Gilles Leymarie as a student side project on a Raspberry Pi in France.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$What does Gladys Plus add?$q$, $q$Gladys Plus is an optional paid subscription that adds encrypted remote access, daily encrypted backups, remote camera streaming, AI model integration, and Enedis electricity monitoring, offered in Lite and Plus tiers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$How is Gladys different from Home Assistant?$q$, $q$Both are open-source, self-hosted home automation platforms, but Gladys focuses more heavily on ease of setup and privacy-first messaging, while Home Assistant has a larger community and broader integration library.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Does Gladys Assistant require an internet connection?$q$, $q$The core automation engine runs locally on your own hardware and does not require sending data to a third-party cloud; remote access outside the home network is available through the optional Gladys Plus subscription.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$What protocols does Gladys Assistant support?$q$, $q$Gladys supports open protocols including Zigbee, Z-Wave, Matter, and MQTT, plus dedicated integrations for brands like Shelly, Sonos, Tuya, and RTSP cameras.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Privacy-conscious smart home setup$q$, $q$Homeowners who do not want their automation data sent to Amazon, Google, or other cloud vendors self-host Gladys on a Raspberry Pi to keep control local.$q$, $q$Privacy-conscious homeowners and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Multi-brand device integration$q$, $q$Users with devices from many different smart home brands use Gladys to unify Zigbee, MQTT, and vendor-specific integrations into one automation layer.$q$, $q$Smart home enthusiasts with mixed-brand device setups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Remote home monitoring and energy tracking$q$, $q$Gladys Plus subscribers use encrypted remote access and Enedis integration to monitor cameras and electricity usage while away from home.$q$, $q$Gladys Plus subscribers, primarily in France$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Free / Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full home automation engine","Zigbee, Matter, MQTT and third-party integrations","Scenario and automation builder","Self-hosted on Raspberry Pi, NAS, or Docker"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Gladys Plus Lite$q$, $q$EUR 5.83/month (EUR 69.99/year)$q$, $q$Monthly or annual$q$, NULL, $q$["End-to-end encrypted remote access","Google Home and Amazon Alexa integration","Open REST API access","Family accounts","1-month free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$Gladys Plus$q$, $q$EUR 8.33/month (EUR 99.99/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Lite","Daily encrypted backups","Remote camera streaming","Open-weight AI model integration","Enedis electricity monitoring","MCP server support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gladys Assistant is an open-source, privacy-first home automation platform founded in 2013 by Pierre-Gilles Leymarie, initially built as a student side project on a Raspberry Pi.$q$, $q$The core software is free, self-hosted, and keeps home automation data on the user's own hardware rather than a vendor's cloud, distinguishing it from mainstream smart home platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gladys supports open protocols like Zigbee, Matter, and MQTT alongside dozens of dedicated device integrations, plus a scenario engine for building automation rules.$q$, $q$Gladys Plus, the optional premium subscription, adds encrypted remote access, daily backups, camera streaming, AI model integration, and Model Context Protocol support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core platform is free and open source, self-hosted with a single Docker command and no subscription required.$q$, $q$Gladys Plus is offered in Lite (about 5.83 euros per month) and Plus (about 8.33 euros per month) tiers, each with a one-month free trial and no long-term commitment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82491f2c-b6b1-4919-82ea-838eafd86db9', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Session Replay$q$, $q$Captures 100 percent of user interactions and technical events across web and mobile, reconstructed as a video-like replay.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Customer journey mapping$q$, $q$Visualizes how users move through key funnels like loan applications or account signups, highlighting drop-off points.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Heatmaps$q$, $q$Shows where users click, scroll, and hesitate across pages and app screens.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Struggle and friction detection$q$, $q$Automatically flags sessions with errors, rage-clicks, or abandonment for faster triage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Glassbox Insights Assistant (GIA)$q$, $q$AI-powered assistant that summarizes sessions and enables natural-language search across recorded sessions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Fraud and anomaly detection$q$, $q$Machine learning identifies abnormal or irregular session activity in real time for security and fraud teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Mobile app monitoring$q$, $q$SDKs capture technical events and user interactions inside native mobile apps, not just web.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Compliance-oriented data capture$q$, $q$Built with data masking and regulatory considerations relevant to banking, insurance, and government customers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Captures 100 percent of sessions rather than a sampled subset, giving complete visibility$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Strong specialization and reputation in regulated industries like banking and insurance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$AI-powered Insights Assistant addresses the scale problem of manually reviewing session replays$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Real-time fraud and anomaly detection adds security value beyond typical UX analytics$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Established company with over a decade of operating history and enterprise customers like Air Canada and Marriott$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$No free tier or transparent self-serve pricing; enterprise sales cycle required$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Estimated costs (roughly 3,000 to 12,000 dollars per month) put it out of reach for smaller companies$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Primarily built for large, regulated enterprises rather than startups or SMBs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Ownership changes (IPO in 2021, taken private by Alicorn in 2024) introduce some uncertainty around long-term strategy$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Competes with well-funded, faster-moving digital experience platforms like Contentsquare and FullStory$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$How much does Glassbox cost?$q$, $q$Glassbox does not publish pricing; it uses a custom, quote-based enterprise sales model, with industry estimates suggesting costs roughly in the 3,000 to 12,000 dollar per month range depending on scale.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Who founded Glassbox?$q$, $q$Glassbox was founded in 2010 in Israel by Yoav Schreiber, Yaron Gueta, and Hanan Blumstein.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$What industries does Glassbox focus on?$q$, $q$Glassbox focuses heavily on regulated industries including financial services, insurance, government, telecom, airlines, and utilities, and states roughly 60 percent of the largest US banks use its platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Is Glassbox a public company?$q$, $q$Glassbox went public on the Tel Aviv Stock Exchange in June 2021 but was acquired and taken private again by private equity firm Alicorn in 2024.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$What is the Glassbox Insights Assistant?$q$, $q$The Glassbox Insights Assistant (GIA) is an AI feature that automatically summarizes recorded sessions and lets analysts search across sessions using natural language.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$What are the main alternatives to Glassbox?$q$, $q$Common alternatives include Contentsquare, FullStory, Quantum Metric, Decibel, and Medallia, though Glassbox differentiates itself through its regulated-industry focus and fraud detection capabilities.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Banking application troubleshooting$q$, $q$Banks use Glassbox Session Replay to see exactly how customers interact with online loan or account applications and identify where they struggle or abandon the process.$q$, $q$Digital banking and financial services teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Fraud investigation$q$, $q$Security and fraud teams use Glassbox's anomaly detection and precise session replays to investigate suspicious account activity in real time.$q$, $q$Fraud and security teams at banks and insurers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Customer experience optimization$q$, $q$Large enterprises use journey mapping and heatmaps to identify and fix friction points across web and mobile customer journeys.$q$, $q$Digital experience and product teams at regulated enterprises$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual contract (typical)$q$, NULL, $q$["Session Replay across web and mobile","Customer journey mapping and heatmaps","Glassbox Insights Assistant (AI)","Fraud and anomaly detection","Compliance-oriented data handling"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Glassbox is an Israeli digital experience analytics company founded in 2010 by Yoav Schreiber, Yaron Gueta, and Hanan Blumstein, focused on session replay and customer intelligence for regulated industries like banking and insurance.$q$, $q$The company went public on the Tel Aviv Stock Exchange in 2021 before being acquired and taken private again by private equity firm Alicorn in 2024.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Glassbox's Session Replay captures 100 percent of user interactions and technical events across web and mobile, reconstructed as a video-like replay rather than relying on sampling.$q$, $q$The Glassbox Insights Assistant applies AI to summarize sessions and let analysts search recorded sessions in natural language, alongside fraud detection and struggle analytics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Glassbox does not offer a free tier or self-serve pricing; all plans are custom-quoted for enterprise customers.$q$, $q$Industry estimates place comparable enterprise session-replay contracts in the range of roughly 3,000 to 12,000 dollars per month depending on scale and features.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('32c09a08-ca8d-4425-b7ea-3b78968f97a4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$100+ pre-built connectors$q$, $q$Native integrations with Slack, Confluence, Google Drive, Salesforce, Jira, GitHub, Zendesk, and dozens of other workplace tools.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Permission-aware indexing$q$, $q$Search results and AI answers respect each source system's original access permissions, so users only see what they are authorized to view.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Glean Assistant$q$, $q$Conversational AI assistant that answers natural-language questions grounded in company-specific knowledge and context.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Glean Apps and APIs$q$, $q$Platform for building custom generative AI agents and applications securely on top of Glean's permissioned enterprise index.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Databricks AI/BI Genie integration$q$, $q$Lets users query structured data in Databricks using natural language directly inside Glean.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Enterprise-grade search relevance$q$, $q$Ranking built on Google-search-derived expertise from founder Arvind Jain's background leading Google Search engineering.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Knowledge management features$q$, $q$Surfaces experts, answers, and trending topics across the organization, not just documents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Security and compliance controls$q$, $q$Enterprise-grade data governance designed for large, regulated organizations deploying AI at scale.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Deep, permission-aware connector library covering 100+ enterprise applications$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Founding team's background at Google Search and Rubrik brings strong technical credibility$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Rapid growth to roughly 200 million dollars in annual recurring revenue reflects strong market validation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Glean Apps and APIs extend the platform beyond search into a full enterprise AI agent builder$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Well-capitalized with roughly 765 million dollars raised, supporting continued R&D investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Pricing is not transparent and typically requires enterprise sales engagement$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Total cost of ownership can run into the hundreds of thousands of dollars annually for larger deployments$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Typical 100-seat minimum puts it out of reach for small and mid-size businesses$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Faces direct competition from Microsoft Copilot, which has natural distribution advantages inside Microsoft 365 shops$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Implementation and integration complexity can add significant upfront cost and time$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$How much does Glean cost?$q$, $q$Glean does not publish list pricing; industry estimates suggest a hybrid model of roughly 45 to 50 dollars per user per month plus an AI add-on of about 15 dollars per user per month, typically with a 100-seat enterprise minimum.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Who founded Glean?$q$, $q$Glean was founded in 2019 in Palo Alto, California, by Arvind Jain, along with Vishwanath T R, Tony Gentilcore, and Piyush Prahladka. Arvind Jain previously co-founded Rubrik and led engineering teams at Google Search.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$What is Glean's current valuation?$q$, $q$Glean was valued at 7.2 billion dollars following a 150 million dollar Series F round led by Wellington Management in June 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$How does Glean handle data permissions?$q$, $q$Glean indexes content from connected apps while preserving each source system's native access permissions, so a user's search results and AI answers only reflect content they are already authorized to see.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$What are Glean's main competitors?$q$, $q$Glean competes with Microsoft Copilot and Microsoft Search, Coveo, Elastic Enterprise Search, Guru, and Moveworks, among other enterprise AI search and assistant platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Does Glean offer an API for building custom AI agents?$q$, $q$Yes, Glean Apps and Glean APIs, launched in mid-2024, let organizations build custom generative AI agents and applications on top of Glean's permissioned enterprise index.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Enterprise knowledge search$q$, $q$Employees use Glean to search across dozens of disconnected workplace tools from a single interface and get relevant, permission-respecting results.$q$, $q$Employees at mid-size to large enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$AI-assisted answers grounded in company data$q$, $q$Teams use Glean Assistant to get natural-language answers synthesized from internal documents, wikis, and tickets instead of manually searching multiple systems.$q$, $q$Knowledge workers across support, sales, and engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Custom AI agent development$q$, $q$Enterprises use Glean Apps and APIs to build custom AI agents that securely leverage the company's permissioned knowledge index.$q$, $q$Enterprise IT and platform engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Enterprise$q$, $q$Custom quote (est. $45-50/user/month base)$q$, $q$Annual, typical 100-user minimum$q$, NULL, $q$["100+ app connectors","Permission-aware search and indexing","Glean Assistant","Enterprise security and governance"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$Enterprise + AI Add-on$q$, $q$Custom quote (+ est. $15/user/month)$q$, $q$Annual$q$, NULL, $q$["Everything in Enterprise","Glean Assistant AI usage","FlexCredits for premium AI features","Glean Apps and APIs access"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Glean is an enterprise AI search and work assistant platform founded in 2019 in Palo Alto by Arvind Jain, former Google search engineering leader and Rubrik co-founder, alongside Vishwanath T R, Tony Gentilcore, and Piyush Prahladka.$q$, $q$The company connects to over 100 workplace applications and became a unicorn in 2022, reaching a 7.2 billion dollar valuation after a 150 million dollar Series F in June 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Glean indexes content across an organization's software stack while preserving each source system's native permissions, so search and AI answers only reflect what a given user is authorized to see.$q$, $q$Glean Assistant provides natural-language answers grounded in company context, while Glean Apps and APIs let organizations build custom AI agents on top of the permissioned index.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Glean does not publish list pricing; industry estimates suggest a hybrid model of roughly 45 to 50 dollars per user per month plus an AI usage add-on, with a typical 100-seat enterprise minimum.$q$, $q$Total cost of ownership for mid-to-large deployments, including implementation and infrastructure, is commonly estimated in the 350,000 to 480,000 dollar annual range.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17dc713-2772-438d-a1a1-bbb8b11b6afc', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Glide AI / Glide Agent$q$, $q$Generates an initial app layout, screen structure, and data schema from a plain-language description of the desired app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Glide Tables$q$, $q$Native data backend that removes the row and update limitations of using an external spreadsheet as an app's data source.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Spreadsheet-to-app conversion$q$, $q$Turns Google Sheets, Airtable, and Excel data into a working, mobile-friendly app with real-time two-way sync.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$AI data extraction$q$, $q$Converts unstructured audio, images, and text into structured data, such as transcribing calls or extracting details from photos.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Workflow automation$q$, $q$Automates tasks like prioritizing support tickets, predicting stock shortages, and drafting customer updates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$40+ UI components$q$, $q$Library of forms, calendars, charts, and other components for building app interfaces without code.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Call API and Glide API$q$, $q$Lets apps call external APIs and exposes Glide's own API for integration with other systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Enterprise integrations$q$, $q$Higher tiers connect to 100+ external data sources including HubSpot, Stripe, QuickBooks, Salesforce, and PostgreSQL.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Especially strong on-ramp for turning existing spreadsheets into usable apps quickly$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Free plan is genuinely usable for individuals and small internal tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$AI app generation lowers the barrier to a working first draft even for non-technical users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Mobile-first output makes apps usable on phones without separate native development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Data privacy commitment states user data is not used to train underlying AI models$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Business plan pricing scales with both users and monthly updates, which can be hard to predict for growing usage$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Free plan is limited to Glide Tables only, not external spreadsheets like Google Sheets$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Enterprise-grade integrations (Salesforce, PostgreSQL, SSO) are locked behind custom Enterprise pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Relatively modest funding (about 23.75 million dollars) compared to larger no-code competitors like Bubble$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Apps are built and hosted within Glide's platform, creating some platform dependency$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Is Glide free to use?$q$, $q$Yes, Glide offers a Free plan with one editor, unlimited draft apps, and up to 25,000 rows using Glide Tables, though it does not support external spreadsheets like Google Sheets on that tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Who founded Glide?$q$, $q$Glide was founded in 2018 by David Siegel, Jason Smith, and Mark Probst, and went through Y Combinator's Winter 2019 batch.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$How much does Glide's Business plan cost?$q$, $q$The Business plan starts at 199 dollars per month billed annually, including 30 users, 5,000 monthly updates, up to 100,000 rows, and support for Google Sheets, Airtable, Excel, and Glide Tables.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$What is Glide AI?$q$, $q$Glide AI, also called the Glide Agent, lets users describe an app in plain language and automatically generates an initial layout, screen structure, and data schema, using multiple large language models.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Does Glide use customer data to train its AI models?$q$, $q$Glide states that data entered by users is protected under an agreement with its AI subprocessor and is not used to further train the underlying AI models.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$What are the main alternatives to Glide?$q$, $q$Common alternatives include Bubble, Adalo, Softr, Google's AppSheet, and Retool, with Glide differentiated by its spreadsheet-to-app on-ramp and AI-driven app generation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Internal operations apps$q$, $q$Operations teams build employee directories, inventory trackers, and approval workflows directly from existing spreadsheets.$q$, $q$Operations and HR teams at small and mid-size businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Field service tools$q$, $q$Field teams use Glide to build mobile checklists and data-collection apps that sync back to a central spreadsheet or database in real time.$q$, $q$Field service and logistics teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Rapid AI-generated prototypes$q$, $q$Non-technical founders and teams use Glide AI to generate a working app prototype from a plain-language description before refining it manually.$q$, $q$Founders and non-technical teams prototyping internal tools$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 editor","Unlimited draft apps","Up to 25,000 rows","Glide Tables only","40+ components","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Business$q$, $q$$199/month$q$, $q$Annual (20% discount vs. monthly)$q$, NULL, $q$["30 included users","5,000 monthly updates","Up to 100,000 rows","Google Sheets, Airtable, Excel, Glide Tables","500GB file storage","10 editors","Workflows and API access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual contract$q$, NULL, $q$["Unlimited apps, users, updates, and rows","100+ data sources including HubSpot, Stripe, Salesforce, PostgreSQL","Single sign-on","Data backups","Dedicated account manager and priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Glide is a no-code app-building platform founded in 2018 through Y Combinator's Winter 2019 batch by David Siegel, Jason Smith, and Mark Probst, letting users turn spreadsheets into functioning web and mobile apps without code.$q$, $q$The company has raised roughly 23.75 million dollars, a relatively lean funding total, and has expanded its data layer beyond spreadsheets into its own native Glide Tables backend.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Glide AI (the Glide Agent) generates an app's layout, screens, and data schema from a plain-language description, using multiple large language models under the hood.$q$, $q$Beyond app generation, Glide's AI can extract structured data from audio, images, and text, and power workflow automation like ticket prioritization and stock shortage prediction.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Glide's Free plan supports one editor and up to 25,000 rows using Glide Tables only, while the Business plan starts at 199 dollars per month for 30 users and 100,000 rows.$q$, $q$Enterprise plans are custom-quoted and remove usage caps while adding 100+ integrations, SSO, and a dedicated account manager.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
