INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd77df40-1f67-4666-a14d-e6d3b6245dbf', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Sentry SDK compatibility$q$, $q$Existing Sentry client libraries can point to a GlitchTip server with no application code changes, only a DSN endpoint change.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$MIT license$q$, $q$Fully open-source and unrestricted, unlike Sentry's later source-available licensing for parts of its codebase.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Lightweight self-hosting$q$, $q$Requires only backend, workers, Redis, and PostgreSQL, running on as little as 1 GB of RAM and a single CPU core.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Hosted cloud plans$q$, $q$Managed hosting tiers from free up to 3 million events per month, running the identical open Docker image used for self-hosting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$EU data hosting$q$, $q$Optional EU-based hosting instance in Germany for data sovereignty requirements.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Unlimited projects and team members$q$, $q$Even the free hosted tier includes unlimited projects and team members, capped only by monthly event volume.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$HIPAA BAA availability$q$, $q$Business Associate Agreements available on request for the Large plan, supporting US healthcare use cases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Non-profit and open-source discounts$q$, $q$Discounted hosted plans starting at 5 dollars per month for verified non-profits and open-source projects.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Genuinely free and open source under the MIT license, with no restricted or gated self-hosted features$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Drop-in compatibility with existing Sentry SDKs makes migration low-friction$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Far simpler self-hosting footprint than Sentry, running on minimal hardware$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Affordable hosted cloud tiers starting free and scaling to 250 dollars per month for 3 million events$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$User-funded, no-VC model keeps incentives aligned with the self-hosting and open-source community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Smaller feature set and analytics depth compared to Sentry's full commercial platform$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Very small maintaining team (a consulting studio) relative to Sentry's larger engineering organization$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Self-hosted deployments still require managing PostgreSQL and Redis infrastructure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Less extensive documentation and third-party ecosystem than the more established Sentry$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$No headquarters or large formal company backing, which some enterprise buyers may view as a support risk$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Is GlitchTip free?$q$, $q$Yes, GlitchTip is free and open source under the MIT license for self-hosting at any scale, and the hosted cloud version also offers a free tier for up to 1,000 events per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Who created GlitchTip?$q$, $q$GlitchTip was created by David Burke of Burke Software and Consulting, reaching its 1.0 release in July 2020.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Is GlitchTip compatible with Sentry?$q$, $q$Yes, GlitchTip is API-compatible with Sentry's official SDKs, so existing Sentry client libraries can be pointed at a GlitchTip server without code changes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$How much does GlitchTip's hosted plan cost?$q$, $q$GlitchTip's hosted plans range from free (1,000 events per month) to 15 dollars for 100,000 events, 50 dollars for 500,000 events, and 250 dollars per month for up to 3 million events.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Is GlitchTip easier to self-host than Sentry?$q$, $q$Yes, GlitchTip requires only four core components (backend, workers, Redis, and PostgreSQL) and can run on as little as 1 GB of RAM, compared to the dozen-plus components required for a full self-hosted Sentry deployment.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$What are the main alternatives to GlitchTip?$q$, $q$The main alternatives are Sentry itself (cloud and self-hosted), along with other error-tracking tools like Bugsink, Rollbar, and Highlight.io.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Self-hosted error tracking$q$, $q$Teams that want full control over error data and infrastructure self-host GlitchTip on minimal hardware using its open Docker image.$q$, $q$Engineering teams with self-hosting or data residency requirements$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Cost-effective Sentry replacement$q$, $q$Teams already using Sentry SDKs switch to GlitchTip's hosted plans to reduce error-tracking costs without changing application code.$q$, $q$Cost-conscious startups and small engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$EU data sovereignty compliance$q$, $q$European organizations use GlitchTip's EU-hosted instance in Germany to keep error and performance data within EU borders.$q$, $q$European companies with data residency requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under MIT license","Sentry SDK compatibility","Unlimited events (self-managed infrastructure)","Runs on minimal hardware"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Hosted Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Up to 1,000 events/month","Unlimited projects and team members","Error tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Hosted Small$q$, $q$$15/month$q$, $q$Monthly$q$, NULL, $q$["Up to 100,000 events/month","Support access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Hosted Medium$q$, $q$$50/month$q$, $q$Monthly$q$, NULL, $q$["Up to 500,000 events/month","Priority email and live chat support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$Hosted Large$q$, $q$$250/month$q$, $q$Monthly$q$, NULL, $q$["Up to 3 million events/month","Prioritized development support","Optional BAA for HIPAA compliance"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GlitchTip is an open-source, Sentry-API-compatible error tracking platform created by David Burke of Burke Software and Consulting, built in direct response to Sentry's move away from permissive open-source licensing.$q$, $q$Released under the MIT license and reaching its 1.0 milestone in July 2020, GlitchTip lets teams point existing Sentry SDKs at a GlitchTip server with no code changes required.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GlitchTip requires only four core components (backend, workers, Redis, and PostgreSQL) compared to the dozen-plus components needed for self-hosted Sentry, and can run on as little as 1 GB of RAM.$q$, $q$The hosted cloud edition runs the identical open-source Docker image used for self-hosting, so cloud customers pay for convenience and support rather than gated features.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting GlitchTip is completely free at any scale under the MIT license, since it uses the same code as the hosted version.$q$, $q$The hosted cloud plans range from a free tier (1,000 events/month) up to 250 dollars per month for 3 million events, with EU hosting and non-profit discounts available.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('640ab266-6f1b-43d9-85ea-0a53ef4f7d1b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
