-- в”Ђв”Ђ Gladys в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Gladys Assistant is a free, open-source, privacy-first home automation platform that runs on a Raspberry Pi or Docker host and connects thousands of smart home devices without sending data to third-party clouds.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Gladys Plus from EUR 5.83/month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$Gladys Assistant Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Gladys Assistant review 2026: the open-source, privacy-first home automation platform's features, self-hosting, Gladys Plus pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Gladys Assistant is an open-source, privacy-first home automation platform that began in 2013 as a student side project. Its founder, Pierre-Gilles Leymarie, was an engineering student experimenting with a Raspberry Pi in his apartment when he started building what would become Gladys, and he has remained the project's lead and CEO as it grew from a hobby build into a small, sustainable software business. Unlike most consumer smart home platforms, which route device data and voice commands through the vendor's cloud servers, Gladys was designed around the opposite principle: home automation logic and device data stay local to the user's own hardware by default, with the software self-hosted on a Raspberry Pi, a NAS, a mini PC, or any Docker-capable machine on the user's home network. This privacy-first architecture has become the project's core identity and differentiator as concerns about smart home vendors collecting and monetizing behavioral data have grown industry-wide. The software itself is fully open source, published on GitHub under the GladysAssistant organization, and can be installed with a single Docker command; there is no subscription requirement, no feature paywall on the core automation engine, and no credit card needed to run it. Gladys supports a broad range of open, non-proprietary protocols including Zigbee, Z-Wave, Matter, and MQTT, alongside dozens of dedicated integrations for popular smart home brands and services such as Shelly, Sonos, Tuya, Netatmo, and RTSP-based IP cameras, letting users mix and match hardware from many manufacturers inside one automation layer. The platform includes a scenario and automation engine for building rules like turning on lights at sunset or adjusting heating based on occupancy, dashboards for visualizing sensor data such as temperature and energy usage over time, and, in more recent versions, integration with AI language models so users can converse with their home setup in natural language rather than only through fixed automation rules. Gladys received a notable form of external validation when Raspberry Pi itself added the Gladys disk image to the official Raspberry Pi Imager tool, making it a one-click install option directly from Raspberry Pi's own installation utility, a distribution channel typically reserved for widely trusted community operating system images. As a business, Gladys operates on a lean, low-headcount model, with public estimates placing the team at roughly 5 to 10 people, and revenue figures reported in community interviews in the low single-digit millions of dollars, funded primarily through its optional premium subscription rather than venture capital, in keeping with the bootstrap ethos common among privacy-focused open-source projects. That premium offering, called Gladys Plus, is what monetizes the otherwise-free platform: it does not gate the core home automation engine but instead unlocks convenience and advanced features that are difficult or costly to self-host securely, most notably encrypted remote access to the user's home automation instance from outside the home network without manually configuring port forwarding or renewing TLS certificates. Gladys Plus is offered in two tiers. The Lite tier, priced at roughly 5.83 euros per month (or 69.99 euros billed annually), includes end-to-end encrypted remote access, Google Home and Amazon Alexa voice assistant integration, open REST API access, and support for family accounts. The Plus tier, at roughly 8.33 euros per month (or 99.99 euros billed annually), adds daily encrypted backups, remote camera streaming, access to open-weight AI models for conversational home control, integration with Enedis (the French electricity distribution operator) for detailed power usage tracking, and support for the Model Context Protocol (MCP), enabling AI agents and assistants to interact with the Gladys instance in a structured way. Both premium tiers include a one-month free trial with no credit card required and can be cancelled at any time without a long-term commitment. Gladys's target audience is technically inclined homeowners and hobbyists who value data ownership and vendor independence over the convenience of a fully cloud-managed system, as well as users in regions like France where the deep Enedis energy-monitoring integration is especially relevant. This audience differs somewhat from the mass-market users of Amazon Alexa or Google Home, and the project instead competes most directly with other open-source, self-hosted home automation platforms, chiefly Home Assistant, which is significantly larger in community size and integration count, along with Jeedom, Domoticz, and openHAB. Gladys differentiates itself within that self-hosted category through a particular emphasis on ease of setup for less technical users, a polished user interface relative to some of its more DIY-feeling open-source peers, and its privacy-by-default framing as the central marketing and product message rather than an afterthought. Overall, Gladys occupies a niche but durable position in the smart home space: it is not trying to out-integrate Home Assistant on raw device count, but instead offers a smaller, French-founded, security-and-privacy-oriented alternative for users who specifically want to avoid sending their home data to Amazon, Google, or other big-tech smart home ecosystems.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '82491f2c-b6b1-4919-82ea-838eafd86db9';

